import 'package:flutter/material.dart';
import 'package:flutter_test/flutter_test.dart';
import 'package:harness_eval/solution.dart';

void main() {
  testWidgets('CounterWidget displays initial value 0', (tester) async {
    await tester.pumpWidget(const MaterialApp(home: CounterWidget()));
    expect(find.text('0'), findsOneWidget);
  });

  testWidgets('CounterWidget increments on FAB tap', (tester) async {
    await tester.pumpWidget(const MaterialApp(home: CounterWidget()));
    await tester.tap(find.byIcon(Icons.add));
    await tester.pump();
    expect(find.text('1'), findsOneWidget);
  });

  testWidgets('CounterWidget increments multiple times', (tester) async {
    await tester.pumpWidget(const MaterialApp(home: CounterWidget()));
    await tester.tap(find.byIcon(Icons.add));
    await tester.pump();
    await tester.tap(find.byIcon(Icons.add));
    await tester.pump();
    expect(find.text('2'), findsOneWidget);
  });
}

import 'package:flutter/material.dart';
import 'package:flutter_test/flutter_test.dart';
import 'package:harness_eval/solution.dart';

void main() {
  testWidgets('TodoListWidget has TextField and add button', (tester) async {
    await tester.pumpWidget(const MaterialApp(home: TodoListWidget()));
    expect(find.byType(TextField), findsOneWidget);
    expect(find.byIcon(Icons.add), findsOneWidget);
  });

  testWidgets('TodoListWidget adds item on button tap', (tester) async {
    await tester.pumpWidget(const MaterialApp(home: TodoListWidget()));
    await tester.enterText(find.byType(TextField), '장보기');
    await tester.tap(find.byIcon(Icons.add));
    await tester.pump();
    expect(find.text('장보기'), findsOneWidget);
  });

  testWidgets('TodoListWidget adds multiple items', (tester) async {
    await tester.pumpWidget(const MaterialApp(home: TodoListWidget()));
    await tester.enterText(find.byType(TextField), '장보기');
    await tester.tap(find.byIcon(Icons.add));
    await tester.pump();
    await tester.enterText(find.byType(TextField), '운동하기');
    await tester.tap(find.byIcon(Icons.add));
    await tester.pump();
    expect(find.text('장보기'), findsOneWidget);
    expect(find.text('운동하기'), findsOneWidget);
  });
}

import 'package:flutter_test/flutter_test.dart';
import 'package:harness_eval/solution.dart';

void main() {
  test('findLongest returns longest string', () {
    expect(findLongest(['apple', 'banana', 'cherry']), equals('banana'));
  });

  test('findLongest returns first longest when tie', () {
    expect(findLongest(['abc', 'def', 'ghi']), equals('abc'));
  });

  test('findLongest returns empty string for empty list', () {
    expect(findLongest([]), equals(''));
  });

  test('findLongest handles single element', () {
    expect(findLongest(['hello']), equals('hello'));
  });
}
